SELECT count(*) FROM cast_info, role_type, char_name, title, movie_keyword, movie_info, keyword, movie_companies WHERE cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_companies.movie_id = title.id;